int n=48; int path[];
for(int i=0;i<n;i++){float a=2.0*M_PI*float(i)/float(n);
int pt=addpoint(0,set(chf("rim_r")*cos(a),0,chf("rim_r")*sin(a)));push(path,pt);}
int prim=addprim(0,"polyline");
for(int i=0;i<len(path);i++)addvertex(0,prim,path[i]);
addvertex(0,prim,path[0]);

